import numpy as np


def make_lag_features(series, n_lags):
    """Turn a 1D time series into a (X, y) supervised problem."""
    n = len(series)
    X = np.full((n, n_lags), np.nan)
    for lag in range(1, n_lags + 1):
        X[lag:, lag - 1] = series[:-lag]
    valid_mask = ~np.isnan(X).any(axis=1)
    return X[valid_mask], series[valid_mask]


def walk_forward_split(n_samples, n_splits=5, min_train=50):
    """Yield (train_slice, test_slice) for walk-forward validation."""
    if n_samples <= min_train:
        return
    step = max(1, (n_samples - min_train) // n_splits)
    for i in range(n_splits):
        train_end = min_train + i * step
        test_end = min(train_end + step, n_samples)
        if train_end >= n_samples:
            break
        yield slice(0, train_end), slice(train_end, test_end)


def autocorrelation(series, max_lag=20):
    """Autocorrelation function (ACF) up to max_lag."""
    n = len(series)
    mean = series.mean()
    var = series.var()
    acf = np.zeros(max_lag + 1)
    for k in range(max_lag + 1):
        if k >= n:
            break
        if var > 0:
            cov = np.mean((series[:n - k] - mean) * (series[k:] - mean))
            acf[k] = cov / var
        else:
            acf[k] = 0.0
    return acf
